head.b:skin:
/* ═══════════════════════════════════════
   NO MERCY PORTFOLIO — Blogger Template
   ═══════════════════════════════════════ */

/* ─── Variables ─── */
:root {
  --bg:       #050510;
  --bg2:      #0a0a1e;
  --surface:  rgba(255,255,255,0.04);
  --border:   rgba(255,255,255,0.08);
  --purple:   #7c3aed;
  --cyan:     #06b6d4;
  --pink:     #ec4899;
  --green:    #10b981;
  --text:     #f1f5f9;
  --muted:    #94a3b8;
  --radius:   16px;
  --font:     'Inter', sans-serif;
  --mono:     'JetBrains Mono', monospace;
  --transition: .3s cubic-bezier(.4,0,.2,1);
}

/* Light mode */
body.light-mode {
  --bg:      #f8fafc;
  --bg2:     #f1f5f9;
  --surface: rgba(0,0,0,0.03);
  --border:  rgba(0,0,0,0.08);
  --text:    #0f172a;
  --muted:   #64748b;
}

/* ─── Reset ─── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }
body {
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
  overflow-x: hidden;
  transition: background var(--transition), color var(--transition);
}
a { text-decoration: none; color: inherit; }
ul { list-style: none; }

::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: var(--bg); }
::-webkit-scrollbar-thumb { background: var(--purple); border-radius: 99px; }

/* ─── Theme toggle ─── */
#theme-toggle {
  position: fixed; bottom: 2rem; right: 2rem; z-index: 999;
  width: 52px; height: 52px; border-radius: 50%;
  background: linear-gradient(135deg, var(--purple), var(--cyan));
  border: none; cursor: pointer; color: #fff;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.2rem;
  box-shadow: 0 4px 20px rgba(124,58,237,.5);
  transition: transform var(--transition), box-shadow var(--transition);
}
#theme-toggle:hover { transform: scale(1.1) rotate(15deg); box-shadow: 0 8px 30px rgba(124,58,237,.7); }

/* ─── Nav ─── */
nav {
  position: fixed; top: 0; left: 0; right: 0; z-index: 100;
  display: flex; align-items: center; justify-content: space-between;
  padding: 1rem 4rem;
  background: rgba(5,5,16,0.75);
  backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border);
  transition: padding var(--transition), background var(--transition);
}
body.light-mode nav { background: rgba(248,250,252,0.85); }
.nav-logo {
  font-size: 1.25rem; font-weight: 800;
  background: linear-gradient(135deg, var(--purple), var(--cyan));
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
}
.nav-links { display: flex; gap: 2rem; align-items: center; }
.nav-links a {
  font-size: .875rem; font-weight: 500; color: var(--muted);
  letter-spacing: .5px; text-transform: uppercase;
  transition: color var(--transition);
  position: relative;
}
.nav-links a::after {
  content: ''; position: absolute; bottom: -4px; left: 0; right: 0;
  height: 2px; background: linear-gradient(90deg, var(--purple), var(--cyan));
  transform: scaleX(0); transition: transform var(--transition); transform-origin: left;
}
.nav-links a:hover { color: var(--text); }
.nav-links a:hover::after { transform: scaleX(1); }
.nav-cta {
  padding: .5rem 1.25rem; border: 1px solid var(--purple);
  border-radius: 99px; color: var(--purple) !important;
  font-weight: 600 !important; transition: background var(--transition), color var(--transition) !important;
}
.nav-cta:hover { background: var(--purple); color: #fff !important; }
.nav-cta::after { display: none !important; }
.hamburger { display: none; background: none; border: none; color: var(--text); font-size: 1.5rem; cursor: pointer; }

/* ─── Page wrapper ─── */
.page { position: relative; z-index: 2; }

/* ─── Sections ─── */
section { padding: 6rem 4rem; max-width: 1200px; margin: 0 auto; }
.section-tag {
  display: inline-flex; align-items: center; gap: .5rem;
  font-family: var(--mono); font-size: .75rem; font-weight: 500;
  color: var(--cyan); text-transform: uppercase; letter-spacing: 2px; margin-bottom: 1rem;
}
.section-tag::before { content: '//'; opacity: .5; }
h2.section-title {
  font-size: clamp(2rem,4vw,3rem); font-weight: 800;
  letter-spacing: -1px; line-height: 1.1; margin-bottom: 1rem;
}
.section-divider {
  width: 60px; height: 3px; border-radius: 99px;
  background: linear-gradient(90deg, var(--purple), var(--cyan)); margin-bottom: 3rem;
}

/* ─── Glass card ─── */
.glass {
  background: var(--surface); border: 1px solid var(--border);
  border-radius: var(--radius); backdrop-filter: blur(12px);
  transition: border-color var(--transition), transform var(--transition), box-shadow var(--transition);
}
.glass:hover {
  border-color: rgba(124,58,237,.4);
  box-shadow: 0 0 30px rgba(124,58,237,.1);
  transform: translateY(-4px);
}

/* ─── HERO ─── */
#hero {
  min-height: 100vh; display: flex; align-items: center;
  justify-content: center; padding: 8rem 4rem 4rem; text-align: center;
}
.hero-inner { max-width: 800px; }
.hero-badge {
  display: inline-flex; align-items: center; gap: .5rem;
  background: rgba(124,58,237,.15); border: 1px solid rgba(124,58,237,.3);
  border-radius: 99px; padding: .4rem 1rem;
  font-size: .8rem; font-weight: 500; color: var(--purple); margin-bottom: 2rem;
  animation: fadeUp .6s ease both;
}
.hero-badge .dot {
  width: 8px; height: 8px; background: var(--green);
  border-radius: 50%; animation: pulse-dot 2s infinite;
}
.hero-name {
  font-size: clamp(3rem,8vw,6rem); font-weight: 900;
  letter-spacing: -3px; line-height: 1; margin-bottom: 1rem;
  background: linear-gradient(135deg,#fff 0%,var(--purple) 40%,var(--cyan) 80%,#fff 100%);
  background-size: 200% auto;
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  animation: shimmer 4s linear infinite, fadeUp .6s .1s ease both;
}
.hero-typing {
  font-family: var(--mono); font-size: 1.1rem; color: var(--cyan);
  margin-bottom: 1.5rem; min-height: 1.8rem;
  animation: fadeUp .6s .2s ease both;
}
.hero-typing .cursor {
  display: inline-block; width: 2px; height: 1.1em;
  background: var(--cyan); margin-left: 2px;
  animation: blink .7s step-end infinite;
  vertical-align: text-bottom;
}
.hero-desc {
  font-size: 1.1rem; color: var(--muted); max-width: 560px;
  margin: 0 auto 2.5rem; animation: fadeUp .6s .3s ease both;
}
.hero-btns {
  display: flex; gap: 1rem; justify-content: center; flex-wrap: wrap;
  animation: fadeUp .6s .4s ease both;
}
.btn {
  display: inline-flex; align-items: center; gap: .5rem;
  padding: .85rem 2rem; border-radius: 99px;
  font-weight: 600; font-size: .95rem;
  transition: all .25s; cursor: pointer; border: none;
}
.btn-primary {
  background: linear-gradient(135deg, var(--purple), var(--cyan));
  color: #fff; box-shadow: 0 0 30px rgba(124,58,237,.4);
}
.btn-primary:hover { transform: translateY(-2px); box-shadow: 0 0 50px rgba(124,58,237,.6); }
.btn-outline {
  background: transparent; border: 1px solid var(--border); color: var(--text);
}
.btn-outline:hover { border-color: var(--purple); background: rgba(124,58,237,.1); }
.hero-scroll {
  margin-top: 4rem; display: flex; flex-direction: column;
  align-items: center; gap: .5rem; color: var(--muted); font-size: .8rem;
  animation: fadeUp .6s .6s ease both;
}
.hero-scroll-line {
  width: 1px; height: 60px;
  background: linear-gradient(to bottom, var(--purple), transparent);
  animation: scrollLine 2s ease-in-out infinite;
}
.hero-stats {
  display: flex; gap: 3rem; justify-content: center; margin-top: 3rem;
  animation: fadeUp .6s .5s ease both;
}
.hero-stat-num {
  font-size: 2rem; font-weight: 900;
  background: linear-gradient(135deg, var(--purple), var(--cyan));
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
}
.hero-stat-label { font-size: .75rem; color: var(--muted); text-transform: uppercase; letter-spacing: 1px; }

/* ─── ABOUT ─── */
#about .about-grid {
  display: grid; grid-template-columns: 1fr 1fr; gap: 4rem; align-items: center;
}
.about-avatar-wrap { position: relative; display: flex; justify-content: center; }
.about-avatar {
  width: 280px; height: 280px; border-radius: 50%;
  background: linear-gradient(135deg, var(--purple), var(--cyan));
  display: flex; align-items: center; justify-content: center;
  font-size: 6rem; position: relative; z-index: 1;
  box-shadow: 0 0 60px rgba(124,58,237,.3);
}
.about-avatar-ring {
  position: absolute; inset: -8px; border-radius: 50%;
  border: 2px solid transparent;
  background: linear-gradient(var(--bg), var(--bg)) padding-box,
              linear-gradient(135deg, var(--purple), var(--cyan)) border-box;
  animation: rotate 8s linear infinite;
}
.about-avatar-ring::after {
  content: ''; position: absolute; width: 16px; height: 16px;
  background: var(--cyan); border-radius: 50%; top: 10px; left: 50%;
  box-shadow: 0 0 10px var(--cyan);
}
.about-info h3 { font-size: 1.8rem; font-weight: 800; margin-bottom: 1rem; }
.about-info p { color: var(--muted); margin-bottom: 2rem; line-height: 1.8; }
.about-facts { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 2rem; }
.about-fact { padding: 1rem; border-radius: 12px; background: var(--surface); border: 1px solid var(--border); }
.about-fact-label { font-size: .75rem; color: var(--muted); text-transform: uppercase; letter-spacing: 1px; margin-bottom: .25rem; }
.about-fact-value { font-weight: 600; font-size: .95rem; }

/* ─── SKILLS ─── */
.skills-grid { display: grid; grid-template-columns: repeat(auto-fit,minmax(260px,1fr)); gap: 1.5rem; }
.skill-card { padding: 1.75rem; border-radius: var(--radius); }
.skill-icon {
  width: 48px; height: 48px; border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.4rem; margin-bottom: 1rem;
}
.skill-card h3 { font-size: 1.1rem; font-weight: 700; margin-bottom: .5rem; }
.skill-card p { font-size: .875rem; color: var(--muted); margin-bottom: 1.25rem; }
.skill-tags { display: flex; flex-wrap: wrap; gap: .4rem; }
.skill-tag {
  font-size: .75rem; padding: .25rem .75rem; border-radius: 99px;
  background: rgba(255,255,255,.06); border: 1px solid var(--border); color: var(--muted);
}
.skill-bar-wrap { margin-top: 1rem; }
.skill-bar-label { display: flex; justify-content: space-between; font-size: .8rem; color: var(--muted); margin-bottom: .4rem; }
.skill-bar { height: 4px; background: rgba(255,255,255,.08); border-radius: 99px; overflow: hidden; }
.skill-bar-fill { height: 100%; border-radius: 99px; background: linear-gradient(90deg,var(--purple),var(--cyan)); width: 0; transition: width 1.2s cubic-bezier(.4,0,.2,1); }

/* ─── PROJECTS ─── */
.projects-grid { display: grid; grid-template-columns: repeat(auto-fit,minmax(340px,1fr)); gap: 1.5rem; }
.project-card { padding: 0; overflow: hidden; }
.project-thumb {
  height: 200px;
  background: linear-gradient(135deg,rgba(124,58,237,.3),rgba(6,182,212,.3));
  display: flex; align-items: center; justify-content: center;
  font-size: 3rem; position: relative; overflow: hidden;
  transition: transform var(--transition);
}
.project-card:hover .project-thumb { transform: scale(1.05); }
.project-thumb::after {
  content: ''; position: absolute; inset: 0;
  background: linear-gradient(to bottom, transparent 50%, rgba(5,5,16,.9));
}
.project-body { padding: 1.5rem; }
.project-tag { font-size: .7rem; font-weight: 600; text-transform: uppercase; letter-spacing: 1px; color: var(--cyan); margin-bottom: .5rem; }
.project-card h3 { font-size: 1.15rem; font-weight: 700; margin-bottom: .5rem; }
.project-card p { font-size: .875rem; color: var(--muted); margin-bottom: 1rem; }
.project-links { display: flex; gap: .75rem; }
.project-link {
  display: inline-flex; align-items: center; gap: .4rem;
  font-size: .8rem; font-weight: 500; color: var(--muted);
  padding: .4rem .9rem; border-radius: 99px;
  border: 1px solid var(--border); transition: all .2s;
}
.project-link:hover { border-color: var(--purple); color: var(--purple); }

/* ─── BLOG POSTS (Blogger native) ─── */
#blog-section { padding: 6rem 4rem; }
.blog-section-inner { max-width: 1200px; margin: 0 auto; }
.blog-grid { display: grid; grid-template-columns: repeat(auto-fit,minmax(300px,1fr)); gap: 1.5rem; }
.blog-card { padding: 1.75rem; display: flex; flex-direction: column; }
.blog-date { font-size: .75rem; color: var(--muted); font-family: var(--mono); margin-bottom: .75rem; }
.blog-card h3 { font-size: 1.1rem; font-weight: 700; margin-bottom: .75rem; line-height: 1.4; }
.blog-card p { font-size: .875rem; color: var(--muted); flex: 1; margin-bottom: 1.25rem; }
.blog-read { display: inline-flex; align-items: center; gap: .4rem; font-size: .85rem; font-weight: 600; color: var(--purple); transition: gap .2s; }
.blog-read:hover { gap: .75rem; }
/* Blogger post widget override */
.post-outer { margin-bottom: 0 !important; }
.post { background: var(--surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 1.75rem; transition: border-color var(--transition), transform var(--transition); }
.post:hover { border-color: rgba(124,58,237,.4); transform: translateY(-4px); }
.post-title { font-size: 1.1rem; font-weight: 700; margin-bottom: .75rem; }
.post-title a { color: var(--text); }
.post-title a:hover { color: var(--purple); }
.post-body { font-size: .875rem; color: var(--muted); }
.post-footer { margin-top: 1rem; }
.post-footer a { font-size: .85rem; font-weight: 600; color: var(--purple); }
.date-header { display: none; }

/* ─── CONTACT ─── */
#contact { text-align: center; }
.contact-wrap { max-width: 640px; margin: 0 auto; }
.social-links { display: flex; gap: 1rem; justify-content: center; flex-wrap: wrap; margin-bottom: 3rem; }
.social-link {
  width: 56px; height: 56px; border-radius: 16px;
  background: var(--surface); border: 1px solid var(--border);
  display: flex; align-items: center; justify-content: center;
  font-size: 1.4rem; transition: all .25s;
}
.social-link:hover { transform: translateY(-4px); border-color: var(--purple); box-shadow: 0 8px 30px rgba(124,58,237,.3); }
.social-link.fb:hover { border-color: #1877f2; box-shadow: 0 8px 30px rgba(24,119,242,.3); }
.social-link.ig:hover { border-color: #e1306c; box-shadow: 0 8px 30px rgba(225,48,108,.3); }
.social-link.yt:hover { border-color: #ff0000; box-shadow: 0 8px 30px rgba(255,0,0,.3); }
.contact-info { display: flex; gap: 2rem; justify-content: center; flex-wrap: wrap; margin-top: 2rem; }
.contact-item { display: flex; align-items: center; gap: .75rem; color: var(--muted); font-size: .9rem; }
.contact-item i { color: var(--purple); }

/* ─── Footer ─── */
footer {
  border-top: 1px solid var(--border); padding: 2rem 4rem;
  display: flex; align-items: center; justify-content: space-between;
  color: var(--muted); font-size: .85rem; position: relative; z-index: 2;
}

/* ─── Reveal animation ─── */
.reveal { opacity: 0; transform: translateY(30px); transition: opacity .7s ease, transform .7s ease; }
.reveal.visible { opacity: 1; transform: translateY(0); }
.reveal-left { opacity: 0; transform: translateX(-30px); transition: opacity .7s ease, transform .7s ease; }
.reveal-left.visible { opacity: 1; transform: translateX(0); }
.reveal-right { opacity: 0; transform: translateX(30px); transition: opacity .7s ease, transform .7s ease; }
.reveal-right.visible { opacity: 1; transform: translateX(0); }

/* ─── Keyframes ─── */
@keyframes fadeUp { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:translateY(0)} }
@keyframes shimmer { to{background-position:200% center} }
@keyframes pulse-dot { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:.5;transform:scale(1.3)} }
@keyframes scrollLine { 0%,100%{opacity:1;transform:scaleY(1)} 50%{opacity:.4;transform:scaleY(.5)} }
@keyframes rotate { to{transform:rotate(360deg)} }
@keyframes blink { 0%,100%{opacity:1} 50%{opacity:0} }
@keyframes float { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-10px)} }

/* ─── Mobile ─── */
@media (max-width:768px) {
  nav { padding: 1rem 1.5rem; }
  .nav-links { display: none; }
  .nav-links.open {
    display: flex; flex-direction: column; position: fixed;
    inset: 0; background: rgba(5,5,16,.97);
    justify-content: center; align-items: center; gap: 2rem; z-index: 99;
  }
  .nav-links.open a { font-size: 1.5rem; }
  .hamburger { display: block; z-index: 100; }
  section, #blog-section { padding: 4rem 1.5rem; }
  #about .about-grid { grid-template-columns: 1fr; }
  .about-avatar { width: 200px; height: 200px; font-size: 4rem; }
  .hero-stats { gap: 1.5rem; }
  footer { flex-direction: column; gap: 1rem; text-align: center; padding: 2rem 1.5rem; }
}

body.script:
//
/* ─── Particle canvas ─── */
const canvas = document.getElementById('bg-canvas');
const ctx = canvas.getContext('2d');
let W, H, particles = [];
function resize() { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; }
resize(); window.addEventListener('resize', resize);
class Particle {
  constructor() { this.reset(); }
  reset() {
    this.x = Math.random() * W; this.y = Math.random() * H;
    this.size = Math.random() * 2 + .5;
    this.speedX = (Math.random() - .5) * .3; this.speedY = (Math.random() - .5) * .3;
    this.opacity = Math.random() * .4 + .1;
    this.hue = Math.random() > .5 ? 270 : 190;
  }
  update() { this.x += this.speedX; this.y += this.speedY; if (this.x < 0 || this.x > W || this.y < 0 || this.y > H) this.reset(); }
  draw() { ctx.beginPath(); ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2); ctx.fillStyle = 'hsla(' + this.hue + ',80%,70%,' + this.opacity + ')'; ctx.fill(); }
}
for (let i = 0; i < 120; i++) particles.push(new Particle());
function drawGlow(x, y, r, color) {
  const g = ctx.createRadialGradient(x, y, 0, x, y, r);
  g.addColorStop(0, color); g.addColorStop(1, 'transparent');
  ctx.fillStyle = g; ctx.beginPath(); ctx.arc(x, y, r, 0, Math.PI * 2); ctx.fill();
}
let t = 0;
function animate() {
  ctx.clearRect(0, 0, W, H); t += .003;
  drawGlow(W*.15+Math.sin(t)*60, H*.3+Math.cos(t*.7)*40, 350, 'rgba(124,58,237,.06)');
  drawGlow(W*.8+Math.cos(t*.8)*50, H*.6+Math.sin(t*1.1)*60, 400, 'rgba(6,182,212,.05)');
  drawGlow(W*.5+Math.sin(t*1.3)*80, H*.8, 300, 'rgba(236,72,153,.04)');
  particles.forEach(p => { p.update(); p.draw(); });
  requestAnimationFrame(animate);
}
animate();

/* ─── Typing effect ─── */
const texts = ['~ No Mercy ~', 'Web Developer 🚀', 'UI/UX Designer 🎨', 'Video Editor 🎬', 'Social Media Expert 📱'];
let textIdx = 0, charIdx = 0, deleting = false;
const typedEl = document.getElementById('typed-text');
function type() {
  const current = texts[textIdx];
  if (!deleting) {
    typedEl.textContent = current.slice(0, ++charIdx);
    if (charIdx === current.length) { deleting = true; setTimeout(type, 2000); return; }
  } else {
    typedEl.textContent = current.slice(0, --charIdx);
    if (charIdx === 0) { deleting = false; textIdx = (textIdx + 1) % texts.length; }
  }
  setTimeout(type, deleting ? 60 : 100);
}
type();

/* ─── Counter animation ─── */
function animateCounter(el, target, suffix) {
  let current = 0;
  const step = target / 60;
  const timer = setInterval(() => {
    current = Math.min(current + step, target);
    el.textContent = Math.floor(current) + (suffix || '+');
    if (current >= target) clearInterval(timer);
  }, 25);
}
const counterObs = new IntersectionObserver(entries => {
  entries.forEach(e => {
    if (e.isIntersecting) {
      animateCounter(document.getElementById('count1'), 20);
      animateCounter(document.getElementById('count2'), 50);
      animateCounter(document.getElementById('count3'), 3);
      counterObs.disconnect();
    }
  });
}, { threshold: 0.5 });
counterObs.observe(document.querySelector('.hero-stats'));

/* ─── Theme toggle ─── */
const themeBtn = document.getElementById('theme-toggle');
const themeIcon = document.getElementById('theme-icon');
const savedTheme = localStorage.getItem('tristar-theme') || 'dark';
if (savedTheme === 'light') { document.body.classList.add('light-mode'); themeIcon.className = 'fas fa-sun'; }
themeBtn.addEventListener('click', () => {
  document.body.classList.toggle('light-mode');
  const isLight = document.body.classList.contains('light-mode');
  themeIcon.className = isLight ? 'fas fa-sun' : 'fas fa-moon';
  localStorage.setItem('tristar-theme', isLight ? 'light' : 'dark');
});

/* ─── Scroll reveal ─── */
const revealEls = document.querySelectorAll('.reveal, .reveal-left, .reveal-right');
const revealObs = new IntersectionObserver(entries => {
  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
}, { threshold: 0.12 });
revealEls.forEach(el => revealObs.observe(el));

/* ─── Skill bars ─── */
const barObs = new IntersectionObserver(entries => {
  entries.forEach(e => {
    if (e.isIntersecting) {
      e.target.querySelectorAll('.skill-bar-fill').forEach(bar => {
        bar.style.width = bar.getAttribute('data-width') + '%';
      });
    }
  });
}, { threshold: 0.3 });
document.querySelectorAll('.skill-card').forEach(c => barObs.observe(c));

/* ─── Hamburger ─── */
const hamburger = document.getElementById('hamburger');
const navLinks = document.getElementById('nav-links');
hamburger.addEventListener('click', () => {
  navLinks.classList.toggle('open');
  hamburger.innerHTML = navLinks.classList.contains('open') ? '<i class="fas fa-times"/>' : '<i class="fas fa-bars"/>';
});
navLinks.querySelectorAll('a').forEach(a => a.addEventListener('click', () => {
  navLinks.classList.remove('open');
  hamburger.innerHTML = '<i class="fas fa-bars"/>';
}));

/* ─── Nav shrink ─── */
window.addEventListener('scroll', () => {
  document.getElementById('navbar').style.padding = window.scrollY > 60 ? '.6rem 4rem' : '1rem 4rem';
});
